import{_ as e,o as a,c as l,a2 as o}from"./chunks/framework.Crpw6aS5.js";const u=JSON.parse('{"title":"内在价值 Intrinsic Value","description":"巴菲特投资哲学的核心：如何计算企业的内在价值","frontmatter":{"title":"内在价值 Intrinsic Value","description":"巴菲特投资哲学的核心：如何计算企业的内在价值"},"headers":[],"relativePath":"02_concepts/intrinsic-value.md","filePath":"02_concepts/intrinsic-value.md"}'),r={name:"02_concepts/intrinsic-value.md"};function n(p,t,i,h,s,d){return a(),l("div",null,[...t[0]||(t[0]=[o('<h1 id="内在价值-intrinsic-value" tabindex="-1">内在价值 Intrinsic Value <a class="header-anchor" href="#内在价值-intrinsic-value" aria-label="Permalink to &quot;内在价值 Intrinsic Value&quot;">​</a></h1><blockquote><p><strong>内在价值</strong>是<a href="/04_people/沃伦·巴菲特.html">巴菲特</a>投资哲学的基石，也是他一切投资决策的核心出发点。在<a href="/04_people/沃伦·巴菲特.html">巴菲特</a>看来，投资的本质就是用低于内在价值的价格买进资产，从而获得安全边际的保护。</p></blockquote><hr><h2 id="核心出处" tabindex="-1">核心出处 <a class="header-anchor" href="#核心出处" aria-label="Permalink to &quot;核心出处&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">年份</th><th style="text-align:left;">重点内容</th></tr></thead><tbody><tr><td style="text-align:left;">**[[/01_letters/1994年/核心总结</td><td style="text-align:left;">1994年]]**</td></tr><tr><td style="text-align:left;">**[[/01_letters/2000年/核心总结</td><td style="text-align:left;">2000年]]**</td></tr><tr><td style="text-align:left;">**[[/01_letters/2007年/核心总结</td><td style="text-align:left;">2007年]]**</td></tr><tr><td style="text-align:left;">**[[/01_letters/2008年/核心总结</td><td style="text-align:left;">2008年]]**</td></tr><tr><td style="text-align:left;">**[[/01_letters/2010年/核心总结</td><td style="text-align:left;">2010年]]**</td></tr><tr><td style="text-align:left;">**[[/01_letters/2019年/核心总结</td><td style="text-align:left;">2019年]]**</td></tr></tbody></table><hr><h2 id="一、什么是内在价值" tabindex="-1">一、什么是内在价值 <a class="header-anchor" href="#一、什么是内在价值" aria-label="Permalink to &quot;一、什么是内在价值&quot;">​</a></h2><p>内在价值（Intrinsic Value）是指一家企业在剩余存续期内能够产生的现金流的贴现值。它是一个<strong>估算值</strong>，而非精确数字。</p><p><a href="/04_people/沃伦·巴菲特.html">巴菲特</a>在1994年致股东信中对此有经典阐述：</p><blockquote><p>&quot;内在价值是一个经济概念，是一家企业在剩余存续期内能够产生的现金流的贴现值。现金流折现法是评估某项业务或金融资产内在价值的唯一逻辑方法。&quot;</p><p>——<a href="/04_people/沃伦·巴菲特.html">沃伦·巴菲特</a>，1994年致股东信</p></blockquote><p>内在价值取决于三个关键变量：</p><ol><li><strong>存续期</strong>——企业还能存活多久</li><li><strong>现金流</strong>——企业未来能产生多少现金</li><li><strong>贴现率</strong>——用多大利率把未来现金流折算成现值</li></ol><hr><h2 id="二、现金流折现-内在价值的计算逻辑" tabindex="-1">二、现金流折现：内在价值的计算逻辑 <a class="header-anchor" href="#二、现金流折现-内在价值的计算逻辑" aria-label="Permalink to &quot;二、现金流折现：内在价值的计算逻辑&quot;">​</a></h2><p><a href="/04_people/沃伦·巴菲特.html">巴菲特</a>采用**现金流折现法（DCF）**来估算内在价值。其核心公式可以简化为：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>内在价值 ≈ 未来现金流之和 ÷ (1 + 贴现率)^n</span></span></code></pre></div><p><a href="/04_people/沃伦·巴菲特.html">巴菲特</a>在2000年致股东信中解释了这一方法背后的逻辑：</p><blockquote><p>&quot;内在价值可以用一个简单的方式来理解：今天口袋里的一美元比明天的一美元更有价值，因为今天的一美元可以立即投入运作。因此，估算一家企业的价值，就是将预期的未来现金流入和流出，按一个适当的利率进行贴现。&quot;</p></blockquote><p><strong>关键参数选择：</strong></p><ul><li><strong>贴现率</strong>：通常使用无风险利率（如长期国债收益率）作为基准</li><li><strong>永续增长率</strong>：假设企业长期以多快的速度增长（通常不超过GDP增速）</li><li><strong>自由现金流</strong>：企业扣除资本支出后真正可自由支配的现金</li></ul><hr><h2 id="三、内在价值与市场价格的区别" tabindex="-1">三、内在价值与市场价格的区别 <a class="header-anchor" href="#三、内在价值与市场价格的区别" aria-label="Permalink to &quot;三、内在价值与市场价格的区别&quot;">​</a></h2><p><a href="/04_people/沃伦·巴菲特.html">巴菲特</a>始终强调，<strong>市场价格并不等于内在价值</strong>。市场往往因为情绪波动而给出错误定价。</p><blockquote><p>&quot;价格是你付出的，价值是你得到的。这两者永远不相等——至少在短期内不会。&quot;</p><p>——<a href="/04_people/沃伦·巴菲特.html">沃伦·巴菲特</a></p></blockquote><p>在2008年金融危机期间，<a href="/04_people/沃伦·巴菲特.html">巴菲特</a>在纽约时报发表署名文章，重申了这一理念：</p><blockquote><p>&quot;从短期来看，市场是一台投票机；但从长期来看，它是一台称重机。恐惧心理在短期内占据主导时，股票会被抛售至远低于其内在价值的价格。&quot;</p><p>——<a href="/04_people/沃伦·巴菲特.html">沃伦·巴菲特</a>，2008年纽约时报文章</p></blockquote><p>正是基于这种认识，<a href="/04_people/沃伦·巴菲特.html">巴菲特</a>能够在市场恐慌时逆势买入优质资产。</p><hr><h2 id="四、安全边际-内在价值的实践意义" tabindex="-1">四、安全边际：内在价值的实践意义 <a class="header-anchor" href="#四、安全边际-内在价值的实践意义" aria-label="Permalink to &quot;四、安全边际：内在价值的实践意义&quot;">​</a></h2><p>知道内在价值后，<a href="/04_people/沃伦·巴菲特.html">巴菲特</a>并不会在价格等于内在价值时买入。他坚持一个核心原则——<strong>安全边际（Margin of Safety）</strong>。</p><p>这一概念由价值投资之父本杰明·<a href="/04_people/本·格雷厄姆.html">格雷厄姆</a>提出，<a href="/04_people/沃伦·巴菲特.html">巴菲特</a>完美继承并实践：</p><blockquote><p>&quot;这句话应该被刻在每个投资者的脑海中：&#39;价格是你付出的，价值是你得到的。&#39;无论多么热爱一家企业，投资者都不应支付过高的价格。&quot;</p><p>——<a href="/04_people/沃伦·巴菲特.html">沃伦·巴菲特</a>，2007年致股东信</p></blockquote><blockquote><p>&quot;当一家强势公司遇到暂时性重大问题时，要提供有吸引力的买入机会，我们就应该做好准备。经济意外是常有的事，但人类恐慌则更加频繁。&quot;</p><p>——<a href="/04_people/沃伦·巴菲特.html">沃伦·巴菲特</a>，2016年致股东信</p></blockquote><p><strong>安全边际的意义：</strong></p><ul><li>为估值偏差提供缓冲</li><li>为市场波动提供保护</li><li>提高了获胜的概率</li></ul><hr><h2 id="五、内在价值的局限性" tabindex="-1">五、内在价值的局限性 <a class="header-anchor" href="#五、内在价值的局限性" aria-label="Permalink to &quot;五、内在价值的局限性&quot;">​</a></h2><p><a href="/04_people/沃伦·巴菲特.html">巴菲特</a>也坦承，内在价值是一个<strong>主观估算</strong>，不同人对同一企业可能得出完全不同的结论：</p><blockquote><p>&quot;内在价值的计算既不是精确的科学，甚至也算不上可靠的艺术。它本质上是一个估计值，而且很大程度上取决于你对企业未来现金流的判断以及你使用的贴现率。&quot;</p><p>——<a href="/04_people/沃伦·巴菲特.html">沃伦·巴菲特</a>，1992年致股东信</p></blockquote><p>这也是为什么<a href="/04_people/沃伦·巴菲特.html">巴菲特</a>始终坚持：<strong>投资自己能力圈内的企业</strong>。只有深入理解一家企业，才能更准确地估算其内在价值。</p><hr><h2 id="六、伯克希尔如何运用内在价值" tabindex="-1">六、<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔</a>如何运用内在价值 <a class="header-anchor" href="#六、伯克希尔如何运用内在价值" aria-label="Permalink to &quot;六、[[伯克希尔]]如何运用内在价值&quot;">​</a></h2><p><a href="/04_people/沃伦·巴菲特.html">巴菲特</a>和<a href="/04_people/查理·芒格.html">芒格</a>每年都会在年报中披露<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔</a>·哈撒韦的内在价值评估方法：</p><blockquote><p>&quot;我们业务和债券的内在价值，远超<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔</a>的账面价值……随着时间推移，账面价值会越来越接近内在价值，尽管这并非直线前进的过程。&quot;</p><p>——<a href="/04_people/沃伦·巴菲特.html">沃伦·巴菲特</a>，2019年致股东信</p></blockquote><p><a href="/04_people/沃伦·巴菲特.html">巴菲特</a>还强调，虽然内在价值无法精确计算，但它<strong>始终是判断投资是否合理的最终标准</strong>：</p><blockquote><p>&quot;我们继续坚持采用内在价值作为我们评估的标准，而不是账面价值……无论我们为收购支付了多高的溢价，只要你确定企业的内在价值稳步增长，你就是一项好的投资。&quot;</p><p>——<a href="/04_people/沃伦·巴菲特.html">沃伦·巴菲特</a>，2010年致股东信</p></blockquote><hr><h2 id="核心要点总结" tabindex="-1">核心要点总结 <a class="header-anchor" href="#核心要点总结" aria-label="Permalink to &quot;核心要点总结&quot;">​</a></h2><table tabindex="0"><thead><tr><th>要素</th><th>说明</th></tr></thead><tbody><tr><td><strong>定义</strong></td><td>企业在剩余存续期内产生的现金流贴现值</td></tr><tr><td><strong>计算方法</strong></td><td>现金流折现法（DCF）</td></tr><tr><td><strong>关键变量</strong></td><td>存续期、自由现金流、贴现率</td></tr><tr><td><strong>与市场价格</strong></td><td>市场价格短期可能大幅偏离内在价值</td></tr><tr><td><strong>安全边际</strong></td><td>买入价应显著低于内在价值</td></tr><tr><td><strong>局限性</strong></td><td>本质上是主观估计，不是精确数字</td></tr></tbody></table><hr><h2 id="相关主题" tabindex="-1">相关主题 <a class="header-anchor" href="#相关主题" aria-label="Permalink to &quot;相关主题&quot;">​</a></h2><ul><li><a href="./moat.html">护城河 (Moat)</a> — 理解企业如何持续创造价值，是估算内在价值的基础</li><li><a href="./circle-of-competence.html">能力圈 (Circle of Competence)</a> — 只投资你真正理解的企业，才能准确估算其内在价值</li><li><a href="./mr-market.html">市场先生 (Mr. Market)</a> — 市场波动如何创造低于内在价值的买入机会</li></ul>',52)])])}const f=e(r,[["render",n]]);export{u as __pageData,f as default};
